let _ccCache = [];
let _ccEditId = null;
let _ccDevNames = {};   // device id -> hostname, for the saved-checks list + edit
function _ccResetForm() {
  _ccEditId = null;
  ['cc-name', 'cc-param', 'cc-target', 'cc-host-search', 'cc-catalog-search', 'cc-window', 'cc-warn', 'cc-crit', 'cc-unit', 'cc-maxage', 'cc-pattern']
    .forEach(id => { const e = document.getElementById(id); if (e) e.value = ''; });
  const ws = document.getElementById('cc-watch-svc'); if (ws) ws.checked = true;
  const pc = document.getElementById('cc-protect'); if (pc) pc.checked = false;
  ['cc-host-results', 'cc-catalog-results'].forEach(id => { const r = document.getElementById(id); if (r) r.hidden = true; });
  const k = document.getElementById('cc-kind'); if (k) k.value = 'all';
  const t = document.getElementById('cc-type'); if (t) t.value = 'process';
  const b = document.getElementById('cc-save-btn'); if (b) b.textContent = 'Add check';
  ccKindChanged(); ccTypeChanged();
}
async function openCustomChecks(kind) {
  _ccKind = kind === 'protect' ? 'protect' : 'ops';
  _ccResetForm();
  const t = document.getElementById('custom-checks-modal-title');
  if (t) t.textContent = _ccKind === 'protect' ? 'Protect check catalog' : 'Check catalog';
  if (_ccKind === 'protect') {          // most useful starting point there
    const ty = document.getElementById('cc-type');
    if (ty) { ty.value = 'dir_baseline'; ccTypeChanged(); }
  }
  // show the dropdown lists when the search boxes get focus (CSP-safe listeners,
  // wired once per element)
  [['cc-catalog-search', ccCatalogSearch], ['cc-host-search', ccHostSearch]].forEach(([id, fn]) => {
    const el = document.getElementById(id);
    if (el && !el._wiredFocus) { el._wiredFocus = 1; el.addEventListener('focus', fn); }
  });
  openModal('custom-checks-modal');
  loadCustomCheckList();
}
// ── Integrity Guard: applied protect checks (Security -> Protect) ──────────
// Same rows as the operational list, filtered to protect checks, so Protect is
// self-contained: apply, review, tune and see what was quarantined in one page.
async function loadProtectChecks() {
  const el = document.getElementById('pc-tbody');
  if (!el) return;
  // Eager wire-up: before the fetch, so the sort indicators are there even
  // while loading (the documented pattern).
  tableCtl.wireSortOnly('pc-thead', 'protectchecks', _pcRender);
  const data = await api('GET', '/checks/custom');
  const checks = (data && data.checks) || [];
  _ccCache = checks;                       // so editCustomCheck(id) resolves
  try {
    const devs = await _scanDeviceList();
    _ccDevNames = {};
    (devs || []).forEach(d => { _ccDevNames[d.id] = d.name || d.id; });
  } catch (_) { /* keep whatever we had */ }
  _pcRows = checks.filter(_ccIsProtect);
  _pcRender();
}
let _pcRows = [];
function _pcScope(c) {
  return c.target_kind === 'all' ? 'whole fleet'
    : c.target_kind === 'host' ? `host: ${_ccDevNames[c.target] || c.target}`
    : `${c.target_kind}: ${c.target}`;
}
function _pcRender() {
  const el = document.getElementById('pc-tbody');
  if (!el) return;
  if (!_pcRows.length) {
    el.innerHTML = '<tr><td colspan="5" class="hint">No protect checks applied yet. Use “Baseline protect checks” for a recommended set, or “Add protect check” to define one.</td></tr>';
    return;
  }
  const rows = tableCtl.sortRows('protectchecks', _pcRows, c => ({
    name: (c.name || '').toLowerCase(),
    type: (c.type || '').toLowerCase(),
    param: (c.param || '').toLowerCase(),
    scope: _pcScope(c).toLowerCase(),
  }));
  // Chunked: a fleet-wide apply can be hundreds of rows.
  tableCtl.renderChunked(el, rows.map(c =>
    `<tr><td class="fw-500">${escHtml(c.name)}</td>` +
    `<td><span class="patch-badge ok fs-11">${escHtml(c.type)}</span>${c.protect === 'quarantine' ? ' <span class="patch-badge fs-11" title="Auto-quarantine is on for this check">guard</span>' : ''}</td>` +
    `<td class="mono-12">${escHtml(c.param)}</td><td class="hint">${escHtml(_pcScope(c))}</td>` +
    `<td><div class="user-actions">` +
    `<button class="btn-icon btn-xs" data-action="editProtectCheck" data-arg="${escAttr(c.id)}" title="Edit this check">${_icon('edit', 14)}</button>` +
    `<button class="btn-icon btn-xs c-danger-outline" data-action="deleteProtectCheck" data-arg="${escAttr(c.id)}" data-arg2="${escAttr(c.name)}" title="Delete">${_icon('trash', 14)}</button>` +
    `</div></td></tr>`), {colspan: 5});
}
function editProtectCheck(id) {
  openCustomChecks('protect');   // the form lives in the modal
  editCustomCheck(id);
}
async function deleteProtectCheck(id, name) {
  if (!await uiConfirm({
        title: 'Delete protect check',
        message: `Delete ${name ? `the "${name}" check` : 'this check'}? It stops evaluating on every host it was applied to. Anything already quarantined stays in the vault.`,
        confirmText: 'Delete', danger: true })) return;
  const r = await api('POST', '/checks/custom/delete', {id});
  if (r && r.ok) { toast('Check deleted', 'info'); loadProtectChecks(); }
  else { toast((r && r.error) || 'Failed', 'error'); }
}

// ── Integrity Guard: the quarantine vault ──────────────────────────────────
// Files a dir_baseline check auto-quarantined. Restore/delete are queued as
// one-shot directives the agent applies on its next check-in.
async function loadGuardVault() {
  const el = document.getElementById('guard-vault-tbody');
  if (!el) return;
  tableCtl.wireSortOnly('guard-vault-thead', 'guardvault', _gvRender);
  const data = await api('GET', '/guard/quarantine');
  _gvRows = (data && data.items) || [];
  _gvRender();
}
let _gvRows = [];
function _gvRender() {
  const el = document.getElementById('guard-vault-tbody');
  if (!el) return;
  if (!_gvRows.length) {
    el.innerHTML = '<tr><td colspan="4" class="hint">Nothing quarantined.</td></tr>';
    return;
  }
  const rows = tableCtl.sortRows('guardvault', _gvRows, i => ({
    device: (i.device || '').toLowerCase(),
    orig: (i.orig || '').toLowerCase(),
    ts: i.ts || 0,
  }));
  tableCtl.renderChunked(el, rows.map(i =>
    `<tr><td class="fw-500">${escHtml(i.device)}</td><td class="mono-12">${escHtml(i.orig)}</td>` +
    `<td class="hint">${escHtml(_fmtTs(i.ts))}</td>` +
    `<td><div class="user-actions">` +
    `<button class="btn-icon btn-xs" title="Restore to its original path" data-action="restoreQuarantine" data-arg="${escAttr(i.device_id)}" data-arg2="${escAttr(i.id)}">${_icon('undo', 14)}</button>` +
    `<button class="btn-icon btn-xs c-danger-outline" title="Delete from the vault" data-action="deleteQuarantine" data-arg="${escAttr(i.device_id)}" data-arg2="${escAttr(i.id)}">${_icon('trash', 14)}</button>` +
    `</div></td></tr>`), {colspan: 4});
}
async function _guardAction(deviceId, id, op, msg) {
  const r = await api('POST', '/guard/action', { device_id: deviceId, id: id, op: op });
  if (r && r.ok) { toast(msg, 'success'); loadGuardVault(); }
  else toast((r && r.error) || 'Failed', 'error');
}
function restoreQuarantine(deviceId, id) {
  return _guardAction(deviceId, id, 'restore', 'Restore queued — the agent applies it on its next check-in');
}
async function deleteQuarantine(deviceId, id) {
  if (typeof uiConfirm === 'function'
      && !await uiConfirm('Delete this quarantined file from the vault? This cannot be undone.')) return;
  return _guardAction(deviceId, id, 'delete', 'Delete queued');
}

// ── v6.2.3: Baseline checks — apply a recommended catalog set to a scope ──────
let _bcCatalog = [];
let _bcKind = 'ops';   // which picker is open: operational vs Protect
async function openBaselineChecks(kind) {
  _bcKind = kind === 'protect' ? 'protect' : 'ops';
  const t = document.getElementById('baseline-checks-title');
  if (t) t.textContent = _bcKind === 'protect' ? 'Baseline protect checks' : 'Baseline checks';
  const el = document.getElementById('bc-catalog');
  if (el) el.innerHTML = _skeletonBlock(4);
  const r = document.getElementById('bc-result'); if (r) r.textContent = '';
  const k = document.getElementById('bc-kind'); if (k) k.value = 'all';
  const hs = document.getElementById('bc-host-search'); if (hs) hs.value = '';
  const bt = document.getElementById('bc-target'); if (bt) bt.value = '';
  // show the device dropdown on focus (CSP-safe, wired once)
  const hse = document.getElementById('bc-host-search');
  if (hse && !hse._wiredFocus) { hse._wiredFocus = 1; hse.addEventListener('focus', bcHostSearch); }
  bcKindChanged();
  openModal('baseline-checks-modal');
  const data = await api('GET', '/checks/baseline-catalog');
  _bcCatalog = (data && data.catalog) || [];
  _bcRenderCatalog();
}
function bcKindChanged() {
  const k = document.getElementById('bc-kind')?.value || 'all';
  document.getElementById('bc-target-grp')?.classList.toggle('hidden', k === 'all');
  const isHost = k === 'host';
  const lbl = document.getElementById('bc-target-label');
  if (lbl) lbl.textContent = isHost ? 'Device' : k === 'tag' ? 'Tag' : 'Group';
  // For a host the plain input is hidden and only holds the picked device id —
  // the visible control is the device typeahead. tag/group keep the text input.
  const inp = document.getElementById('bc-target');
  if (inp) {
    inp.classList.toggle('hidden', isHost);
    inp.placeholder = isHost ? '' : k === 'tag' ? 'tag name' : 'group name';
    if (isHost) inp.value = '';
  }
  document.getElementById('bc-host-pick')?.classList.toggle('hidden', !isHost);
}
// Host target is a device search typeahead (never a raw id field) — mirrors the
// custom-check host picker so a baseline check can be applied to one device.
async function bcHostSearch() {
  const box = document.getElementById('bc-host-results');
  if (!box) return;
  const term = (document.getElementById('bc-host-search')?.value || '').toLowerCase().trim();
  const devs = await _scanDeviceList();
  let matches = Array.isArray(devs) ? devs : [];
  if (term) matches = matches.filter(d =>
    (d.name || '').toLowerCase().includes(term) || (d.ip || '').toLowerCase().includes(term) ||
    (d.group || '').toLowerCase().includes(term) || (d.tags || []).some(t => (t || '').toLowerCase().includes(term)));
  matches = matches.slice(0, 25);
  box.innerHTML = matches.length
    ? matches.map(d => `<div class="dev-combo-item" data-action="pickBcHost" data-arg="${escAttr(d.id)}" data-arg2="${escAttr(d.name || d.id)}">${escHtml(d.name || d.id)}${d.ip ? ` <span class="hint">${escHtml(d.ip)}</span>` : ''}</div>`).join('')
    : '<div class="dev-combo-empty">No matching devices.</div>';
  box.hidden = false;
}
function pickBcHost(id, name) {
  const t = document.getElementById('bc-target'); if (t) t.value = id;
  const s = document.getElementById('bc-host-search'); if (s) s.value = name;
  const box = document.getElementById('bc-host-results'); if (box) box.hidden = true;
}
function _bcRenderCatalog() {
  const el = document.getElementById('bc-catalog');
  if (!el) return;

  const cats = {};
  // A row with no kind (older server) is operational, so an out-of-date
  // backend still fills the Checks picker rather than showing nothing.
  _bcCatalog.filter(t => (t.kind || 'ops') === _bcKind)
    .forEach(t => { (cats[t.cat] = cats[t.cat] || []).push(t); });
  if (!Object.keys(cats).length) {
    el.innerHTML = '<div class="empty-state">No templates available.</div>'; return;
  }
  el.innerHTML = Object.keys(cats).map(cat =>
    `<div class="section-title bc-cat">${escHtml(cat)}</div>` +
    cats[cat].map(t =>
      `<label class="bc-row"><input type="checkbox" class="bc-chk" value="${escAttr(t.id)}">` +
      `<span class="bc-row-body">` +
        `<span class="bc-row-head">` +
          `<span class="bc-row-name">${escHtml(t.name)}</span>` +
          `<span class="patch-badge ok fs-11">${escHtml(t.type)}</span>` +
          (t.target_kind
            ? `<span class="bc-row-scope">${escHtml(t.target_kind)}: ${escHtml(t.target || '')}</span>`
            : '') +
        `</span>` +
        `<span class="bc-row-desc">${escHtml(t.desc || '')}</span>` +
      `</span></label>`
    ).join('')
  ).join('');
}
async function applyBaselineChecks() {
  const ids = Array.from(document.querySelectorAll('#bc-catalog .bc-chk:checked')).map(c => c.value);
  if (!ids.length) { toast('Select at least one check', 'error', {transient: true}); return; }
  const tk = document.getElementById('bc-kind')?.value || 'all';
  const tv = (document.getElementById('bc-target')?.value || '').trim();
  if (tk !== 'all' && !tv) { toast('Enter a ' + tk + ' name', 'error'); return; }
  const r = await api('POST', '/checks/baseline-apply', { ids, target_kind: tk, target: tv });
  if (r && r.ok) {
    toast(`Applied — ${r.added} check(s) added${r.added === 0 ? ' (already present)' : ''}`, 'success');
    closeModal('baseline-checks-modal');
    if (typeof loadChecks === 'function') loadChecks();
  } else toast((r && r.error) || 'Failed', 'error');
}

async function loadCustomCheckList() {
  const el = document.getElementById('cc-list');
  if (!el) return;
  const data = await api('GET', '/checks/custom');
  const checks = (data && data.checks) || [];
  _ccCache = checks;   // cache stays COMPLETE so editCustomCheck(id) always resolves
  // Resolve host device ids -> hostnames for display (never show the raw id).
  try {
    const devs = await _scanDeviceList();
    _ccDevNames = {};
    (devs || []).forEach(d => { _ccDevNames[d.id] = d.name || d.id; });
  } catch (_) { /* keep whatever we had */ }
  // Protect checks are managed on Security -> Protect, so keep them out of the
  // operational list (and vice versa) — the Checks RESULTS table still shows
  // every check regardless, so nothing becomes invisible.
  const shown = checks.filter(c => (_ccKind === 'protect') === _ccIsProtect(c));
  if (!shown.length) {
    el.innerHTML = `<div class="empty-state">No ${_ccKind === 'protect' ? 'protect' : 'custom'} checks yet.</div>`;
    return;
  }
  const scope = c => c.target_kind === 'all' ? 'whole fleet'
    : c.target_kind === 'host' ? `host: ${escHtml(_ccDevNames[c.target] || c.target)}`
    : `${c.target_kind}: ${escHtml(c.target)}`;
  const editBtn = id => `<button class="btn-icon btn-xs" data-action="editCustomCheck" data-arg="${escAttr(id)}" title="Edit this check">${_icon('edit',14)}</button><button class="btn-icon btn-xs" data-action="duplicateCustomCheck" data-arg="${escAttr(id)}" title="Duplicate — prefill a new check from this one">${_icon('copy',14)}</button>`;
  el.innerHTML = `<div class="table-card"><table><thead><tr><th>Name</th><th>Type</th><th>Param</th><th>Applies to</th><th></th></tr></thead><tbody>${
    shown.map(c => `<tr><td class="fw-500">${escHtml(c.name)}</td><td><span class="patch-badge ok fs-11">${escHtml(c.type)}</span></td><td class="mono-12">${escHtml(c.param)}</td><td class="hint">${scope(c)}</td><td><div class="user-actions">${editBtn(c.id)}<button class="btn-icon btn-xs c-danger-outline" title="Delete" data-action="deleteCustomCheck" data-arg="${escAttr(c.id)}" data-arg2="${escAttr(c.name)}">${_icon('trash',14)}</button></div></td></tr>`).join('')
  }</tbody></table></div>`;
}
function editCustomCheck(id) {
  const c = (_ccCache || []).find(x => x.id === id);
  if (!c) { toast('Check not found', 'error'); return; }
  _ccEditId = id;
  const setv = (eid, v) => { const e = document.getElementById(eid); if (e) e.value = (v === undefined || v === null) ? '' : v; };
  setv('cc-name', c.name); setv('cc-type', c.type || 'process'); setv('cc-param', c.param);
  setv('cc-kind', c.target_kind || 'all'); setv('cc-target', c.target);
  // host targets: show the device's HOSTNAME (not the raw id) in the search field
  if ((c.target_kind || 'all') === 'host') setv('cc-host-search', _ccDevNames[c.target] || c.target);
  setv('cc-window', c.window_min); setv('cc-warn', c.warn); setv('cc-crit', c.crit);
  setv('cc-unit', c.unit); setv('cc-maxage', c.max_age_hours);
  const pc = document.getElementById('cc-protect'); if (pc) pc.checked = c.protect === 'quarantine';
  setv('cc-pattern', c.pattern);
  ccKindChanged(); ccTypeChanged();
  const b = document.getElementById('cc-save-btn'); if (b) b.textContent = 'Save changes';
  const nm = document.getElementById('cc-name'); if (nm) nm.focus();
}
// v6.3.0 (UX wave 8): duplicate — the clone-as-prefill pattern: reuse the
// edit prefill, then detach from the source id so saving ADDS a new check.
function duplicateCustomCheck(id) {
  editCustomCheck(id);
  _ccEditId = null;
  const nm = document.getElementById('cc-name');
  if (nm) nm.value = (nm.value || 'check') + ' (copy)';
  const b = document.getElementById('cc-save-btn');
  if (b) b.textContent = 'Add check';
  toast('Prefilled — saving adds a new check', 'info');
}

async function saveCustomCheck() {
  const body = {
    name: document.getElementById('cc-name')?.value.trim() || '',
    type: document.getElementById('cc-type')?.value || 'process',
    param: document.getElementById('cc-param')?.value.trim() || '',
    target_kind: document.getElementById('cc-kind')?.value || 'all',
    target: document.getElementById('cc-target')?.value.trim() || '',
  };
  if (_ccEditId) body.id = _ccEditId;   // update-in-place keyed on id
  if (!body.param) { toast('A value is required', 'error', {transient: true}); return; }
  const numOf = id => { const v = parseInt(document.getElementById(id)?.value, 10); return isNaN(v) ? undefined : v; };
  if (body.type === 'log_errors') {
    body.window_min = numOf('cc-window');
    body.warn = numOf('cc-warn');
    body.crit = numOf('cc-crit');
    body.unit = document.getElementById('cc-unit')?.value.trim() || '';
  } else if (body.type === 'job_fresh') {
    body.max_age_hours = numOf('cc-maxage');
  } else if (body.type === 'systemd_unit' && body.target_kind === 'host') {
    // wire to the Services page: also watch this unit on the targeted host
    body.watch_service = !!document.getElementById('cc-watch-svc')?.checked;
  } else if (body.type === 'file_contains') {
    body.pattern = document.getElementById('cc-pattern')?.value.trim() || '';
    if (!body.pattern) { toast('A search pattern is required', 'error', {transient: true}); return; }
  } else if (body.type === 'dir_baseline') {
    // Integrity Guard: opt into auto-quarantine of new files
    if (document.getElementById('cc-protect')?.checked) body.protect = 'quarantine';
  }
  const r = await api('POST', '/checks/custom', body);
  if (r && r.ok) {
    toast(_ccEditId ? 'Custom check saved' : 'Custom check added', 'success');
    _ccResetForm();
    loadCustomCheckList();
  } else { toast((r && r.error) || 'Failed', 'error'); }
}
async function deleteCustomCheck(id, name) {
  if (!await uiConfirm({
        title: 'Delete check',
        message: `Delete ${name ? `the "${name}" check` : 'this custom check'}? It stops evaluating on every host it was applied to.`,
        confirmText: 'Delete', danger: true })) return;
  const r = await api('POST', '/checks/custom/delete', {id});
  if (r && r.ok) { toast('Check deleted', 'info'); loadCustomCheckList(); }
  else { toast((r && r.error) || 'Failed', 'error'); }
}
